// 1. Generate a random 4-digit complaint number
const complaintNumber = Math.floor(1000 + Math.random() * 9000);

// 2. Generate dates
const today = new Date();
const expectedDate = new Date();
expectedDate.setDate(today.getDate() + 5);

// 3. Attach new fields to the existing data ($json)
// This preserves the "output" from your AI Agent node
$json.complaintId = `C-${complaintNumber}`;
$json.submittedDate = today.toLocaleDateString('en-IN'); 
$json.expectedResolutionDate = expectedDate.toLocaleDateString('en-IN');

// 4. Return the updated item
return $json;
